INSERT INTO public.photos VALUES (21986, 'Gran Vâ”œÂ¡a 1949', 'Vista de la prolongaciâ”œâ”‚n de la Gran Vâ”œÂ¡a capturada desde la torre de la Feria Nacional de Muestras. A la izquierda, construcciâ”œâ”‚n de la Residencia Sanitaria Josâ”œÂ® Antonio, comenzada en 1948 y terminada en 1955. A la derecha, acequia de la Romareda. Sobre el firme de la calle, obras para la lâ”œÂ¡nea 15 "Casablanca" del tranvâ”œÂ¡a, que unirâ”œÃ­ ese barrio con la plaza de Espaâ”œâ–’a en 1950. Fuente: www.facebook.com/photo.php?fbid=10209509669832229&set...', 1949, 1949, 1949, 'Anos 40', 'UNIVERSIDAD', 41.63631300, -0.90024300, '0101000020E6100000637E6E68CACEECBF848252B472D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30082891026.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30082891026.webp', 'https://www.flickr.com/photos/zaragozaantigua/30082891026/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21993, 'Pedro Cerbuna 1949', 'Imagen capturada por F. Mesas (Bilbao) y convertida en postal, de las instalaciones ocupadas en el Cuartel de Palafox por el Regimiento de Montaâ”œâ–’a nâ”¬â•‘ 20, correspondientes a las residencias de oficiales y suboficiales. Varias dâ”œÂ®cadas despuâ”œÂ®s, y tras la "Operaciâ”œâ”‚n Cuarteles", el edificio de primer plano, angular entre las calle de Domingo Miral (izquierda) y Pedro Cerbuna (al fondo), serâ”œÂ¡a reconvertido en cuartel de la policâ”œÂ¡a local. El edificio del fondo, esquinero con la calle de Manuel Serrano Sanz, serâ”œÃ­ remodelado y elevado una planta, para convertirlo en la Residencia Logâ”œÂ¡stica Militar "Palafox". Fuente visual: www.todocoleccion.net/', 1949, 1949, 1949, 'Anos 40', 'UNIVERSIDAD', 41.63961500, -0.89882800, '0101000020E6100000B05417F032C3ECBFF98381E7DED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31196548754.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31196548754.webp', 'https://www.flickr.com/photos/zaragozaantigua/31196548754/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22028, 'P.â”¬â•‘ de Isabel la Catâ”œâ”‚lica c.1946', 'Imagen capturada en el adoquinado paseo reciâ”œÂ®n denominado de Isabel la Catâ”œâ”‚lica, con el aspecto de esta perifâ”œÂ®rica zona flanqueada a la izquierda por el moderno convento de Jerusalâ”œÂ®n (desde 1943), y a la derecha por el Colegio-Residencia de Nuestra Seâ”œâ–’ora del Pilar para Huâ”œÂ®rfanos e Hijos del Magisterio que, proyectado en 1943 por Rafael F. Huidobro, Josâ”œÂ® Beltrâ”œÃ­n, Regino Borobio y Josâ”œÂ® Borobio, tuvo un dilatado proceso constructivo, para ser finalmente inaugurado en 1957. Al fondo, la rutilante atalaya de la Feria de Muestras, los nuevos bloques de viviendas del paseo de Fernando el Catâ”œâ”‚lico, e incluso la torre del colegio La Salle Gran Vâ”œÂ¡a, heredada del original y fallido convento e Iglesia de los Carmelitas Descalzos.', 1946, 1946, 1946, 'Anos 40', 'UNIVERSIDAD', 41.63400000, -0.90303500, '0101000020E6100000689604A8A9E5ECBFFED478E926D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50642257527.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50642257527.webp', 'https://www.flickr.com/photos/zaragozaantigua/50642257527/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22410, 'Monumento a la Madre 1967', 'En 1965, la emisora "Radio Popular", reciente invento propagandâ”œÂ¡stico de la Conferencia Episcopal Espaâ”œâ–’ola, propuso erigir un monumento que homenajease a "la Madre". Se realizâ”œâ”‚ una recogida de donativos, y con la colaboraciâ”œâ”‚n municipal se localizâ”œâ”‚ su emplazamiento en el parque Primo de Rivera, junto a una zona de juegos infantiles. Los promotores de la idea pretendâ”œÂ¡an que el homenaje fuera tanto a la "madre terrena", como "a la del cielo", y casi se meten en un lâ”œÂ¡o, pues eso hubiera supuesto erigir un nuevo santuario de la singular "Madre del Cielo", o "Virgen del Pilar", fuera del espacio de su habitual columna. La cosa se reencauzâ”œâ”‚, dejando que este monumento fuera "sâ”œâ”‚lo" a la terrenal madre. Un joven â”œÃ¼ngel Orensanz fue seâ”œâ–’alado para realizar los bultos redondos del grupo escultâ”œâ”‚rico, tallado en piedra de Ulldecona (Tarragona), que representa a una joven figura maternal en actitud protectora de un niâ”œâ–’o. Junto a ellos, un bloque de piedra reza "A la Madre. Levantâ”œâ”‚ el pueblo de Aragâ”œâ”‚n este monumento por iniciativa de Radio Popular". En la imagen, inauguraciâ”œâ”‚n del monumento, con presencia de numerosas autoridades religiosas, militares e institucionales, amâ”œÂ®n de bastante gente de a pie. Fuente visual: Gerardo Sancho Ramo, Archivo Pâ”œâ•‘blico Municipal.', 1967, 1967, 1967, 'Anos 60', 'UNIVERSIDAD', 41.63202700, -0.89784200, '0101000020E61000001A355F251FBBECBF3198BF42E6D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24706498900.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24706498900.webp', 'https://www.flickr.com/photos/zaragozaantigua/24706498900/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22413, 'Cuartel Palafox 1965', 'El franquismo resultâ”œâ”‚ ser una continuidad de la guerra civil por otras vâ”œÂ¡as. Su perenne vinculaciâ”œâ”‚n con la guerra, que fue su epifanâ”œÂ¡a, se reforzaba con la exaltaciâ”œâ”‚n de los sâ”œÂ¡mbolos que recordaban esa â”œÂ¡ntima uniâ”œâ”‚n. La memoria de los caâ”œÂ¡dos (propios) en combate, y el homenaje a las organizaciones de excombatientes franquistas, formaban parte de esa cultura de guerra, aunque aparentemente se conmemorara la "paz". Lejos de "olvidar" el pasado, de "pasar pâ”œÃ­gina", se trataba de recordar, actualizar y mantener viva la memoria de la guerra en forma de ceremonias, actos pâ”œâ•‘blicos, homenajes, desfiles, participaciâ”œâ”‚n en organizaciones y hermandades de excombatientes, mutilados o no... La imagen ha sido capturada durante la VIII Asamblea de la Hermandad Provincial de Alfâ”œÂ®reces Provisionales, en uno de los patios internos del cuartel de Palafox, de artillerâ”œÂ¡a de montaâ”œâ–’a. Una misa al aire libre como parte del programa de actos, con una cobertera para proteger del canicular sol zaragozano, fuera de temporada. Al fondo, edificios del paseo de Fernando el Catâ”œâ”‚lico, y de la calle de Luis Vives. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1965, 1965, 1965, 'Anos 60', 'UNIVERSIDAD', 41.63974300, -0.90029700, '0101000020E61000002FFB75A73BCFECBF276C3F19E3D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25071591582.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25071591582.webp', 'https://www.flickr.com/photos/zaragozaantigua/25071591582/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22418, 'Feria de Muestras 1964', 'Imagen en altura, desde la torre de la Feria de Muestras, del interior del recinto ferial, posiblemente durante el primero de los certâ”œÃ­menes dedicado monogrâ”œÃ­ficamente a la maquinaria agrâ”œÂ¡cola. A la izquierda, el cubierto y referencial "Pabellâ”œâ”‚n Francâ”œÂ®s", inaugurado en 1958, como doble homenaje al asedio francâ”œÂ®s de 1808, y a la exposiciâ”œâ”‚n hispano-francesa de 1908. A la derecha, vista parcial del Cuartel de Palafox. El acople de otra fotografâ”œÂ¡a, en la parte superior, origina una extraâ”œâ–’a sensaciâ”œâ”‚n en una zona que, por esos aâ”œâ–’os, asomaba a campos de cultivo, aâ”œâ•‘n sin edificar. Fuente visual: Estudio Coyne (DARA-AHPZ).', 1964, 1964, 1964, 'Anos 60', 'UNIVERSIDAD', 41.63751500, -0.89931400, '0101000020E6100000DCB75A272EC7ECBFCFDA6D179AD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26248236173.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26248236173.webp', 'https://www.flickr.com/photos/zaragozaantigua/26248236173/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22547, 'Campus Universidad 1975', 'Archivo Histâ”œâ”‚rico Municipal. Gerardo Sancho Ramo. 21/09/1975. Campus Universidad Plaza San Francisco. Edificio Interfacultades. Expresivo grafitti (aerosol sobre plantilla) que representa câ”œâ”‚mo sobre un cerdo comunista estâ”œÃ­ a punto de abatirse, sin que San Antâ”œâ”‚n intervenga, la soluciâ”œâ”‚n final en forma de tremendo cuchillo nazi. Se nota que quien ha dibujado el cuchillo ha participado en pocas matacâ”œÂ¡as de verdad.', 1975, 1975, 1975, 'Anos 70', 'UNIVERSIDAD', 41.64233100, -0.89799200, '0101000020E61000006D3A02B859BCECBF7E1AF7E637D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15016515750.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15016515750.webp', 'https://www.flickr.com/photos/zaragozaantigua/15016515750/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22605, 'Palacio Municipal de los Deportes 1976', 'Imagen de la construcciâ”œâ”‚n del Palacio de los Deportes de Zaragoza, capturada en altura desde la confluencia de las calles Asâ”œÂ¡n y Palacios, y Luis Bermejo. Al fondo, los grandes megabloques habitacionales que estaban surgiendo en la confluencia de San Juan Bosco y lo que luego serâ”œÂ¡a denominado "Vâ”œÂ¡a Universitas". La local costumbre de ponerle varios nombres a los sitios bautizâ”œâ”‚ pronto a esta pâ”œâ•‘blica instalaciâ”œâ”‚n como "El Huevo", por la ovalada culminaciâ”œâ”‚n de su cubierta. Esta es una de las razones por las que los foranos y turistas se lo pasan pipa cuando intentan localizar esta, u otra instalaciâ”œâ”‚n. Este Palacio de los Deportes de Zaragoza fue inaugurado en setiembre de 1977, con el I Trofeo de Baloncesto "Ciudad de Zaragoza" entre las selecciones absolutas de Espaâ”œâ–’a, Francia, Uniâ”œâ”‚n Soviâ”œÂ®tica, y la universitaria de Cuba. Antonio Dâ”œÂ¡az-Miguel seleccionâ”œâ”‚ por Espaâ”œâ–’a a Brabender, Cabrera, Prada, Corbalâ”œÃ­n, Rullâ”œÃ­n, Josâ”œÂ® Marâ”œÂ¡a Margall, Santillana, Filbâ”œÃ­, Fernâ”œÃ­ndez, Flores, De la Cruz, Gonzalo Sagi-Vela y Vicente Gil. La Uniâ”œâ”‚n Soviâ”œÂ®tica de Aleksandr Gomelsky fue la vencedora del torneo, con Serguâ”œÂ®i Belov, Ivâ”œÃ­n Edeshko, Jurij Pavlov, Valeri Miloserdov, Aleksandr Boloshev, Alzhan Zharmujamedov, Aleksandr Belov, Aleksandr Salnikov, Mijaâ”œÂ¡l Korkia, Vladâ”œÂ¡mir Zhigili. Fuente visual: Archivo Pâ”œâ•‘blico Municipal. Gerardo Sancho Ramo.', 1976, 1976, 1976, 'Anos 70', 'UNIVERSIDAD', 41.63975400, -0.90414900, '0101000020E61000005DC136E2C9EEECBF1BBE8575E3D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18795439299.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18795439299.webp', 'https://www.flickr.com/photos/zaragozaantigua/18795439299/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22606, 'Fernando el Catâ”œâ”‚lico 1976', 'Torre de la Editorial Luis Vives, ubicada entre 1941 y 1975 en el paseo de Fernando el Catâ”œâ”‚lico nâ”¬â•‘ 63, en una imagen cuando las instalaciones y talleres ya se habâ”œÂ¡an trasladado al extrarradio urbano, y apenas quedaban los muros perimetrales y sus jardines y zonas verdes. La torre, demediada de su cuerpo superior, serâ”œÂ¡a poco despuâ”œÂ®s derribada, y sobre este cotizado espacio se construirâ”œÂ¡a despuâ”œÂ®s una compacta manzana de bloques de viviendas.', 1976, 1976, 1976, 'Anos 70', 'UNIVERSIDAD', 41.63825300, -0.89686100, '0101000020E6100000F5D901D715B3ECBF75C93846B2D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18881848032.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18881848032.webp', 'https://www.flickr.com/photos/zaragozaantigua/18881848032/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22616, 'Pabellâ”œâ”‚n de Deportes 1973', 'Con este dibujo se anunciaba a comienzos de 1973 la futura construcciâ”œâ”‚n del Pabellâ”œâ”‚n Municipal de Deportes de Zaragoza, en el barrio de la Romareda. Su aspecto definitivo distâ”œâ”‚ mucho del mostrado, siendo bautizado por la ciudadanâ”œÂ¡a como "el huevo", tras su inauguraciâ”œâ”‚n en 1977. En primer plano, la entrada principal, en la calle de los Condes de Aragâ”œâ”‚n. Fuente: Diario Amanecer, 13 de enero de 1973.', 1973, 1973, 1973, 'Anos 70', 'UNIVERSIDAD', 41.63975400, -0.90414900, '0101000020E61000005DC136E2C9EEECBF1BBE8575E3D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19218313098.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19218313098.webp', 'https://www.flickr.com/photos/zaragozaantigua/19218313098/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22770, 'Hugh Thomas 1976', 'Imagen del historiador e hispanista britâ”œÃ­nico Hugh Thomas, capturada durante su conferencia organizada en el mes de febrero por una poderosa e influyente entidad de ahorro local en el polideportivo de su propiedad en el polâ”œÂ¡gono Romareda. Reciâ”œÂ®n pasado del Partido Laborista al Partido Conservador, su presencia en la Espaâ”œâ–’a en esa â”œÂ®poca fue considerada una muestra mâ”œÃ­s de la apertura del Râ”œÂ®gimen Franquista que, en este caso, sirviâ”œâ”‚ para dar a conocer al gran pâ”œâ•‘blico la obra de Thomas del aâ”œâ–’o 1961 titulada "La guerra civil espaâ”œâ–’ola", publicada en la editorial Ruedo Ibâ”œÂ®rico. Como los tiempos eran los que eran, en la rueda de prensa previa al acto, realizada en la Casa del Deâ”œÃ­n, a Thomas le preguntaron por el "Generalâ”œÂ¡simo" Franco, fallecido no hacâ”œÂ¡a mucho, a lo que el britâ”œÃ­nico respondiâ”œâ”‚ que fue un "hombre bueno", un "militar arriesgado en su juventud", un "generalâ”œÂ¡simo muy cauteloso", y un "estadista prudente". Preguntado por Fraga Iribarne, respondiâ”œâ”‚ que era "un hombre culto que podrâ”œÂ¡a ser primer ministro (presidente del Gobierno) de una Espaâ”œâ–’a democrâ”œÃ­tica". Con estos antecedentes, el â”œÂ®xito de crâ”œÂ¡tica y pâ”œâ•‘blico mayoritario estaba mâ”œÃ­s que garantizado. Desde 1981, Thomas fue asesor para asuntos hispâ”œÃ­nicos de la primera ministra Margaret Thatcher. Fue nombrado lord de Inglaterra, y Espaâ”œâ–’a le concediâ”œâ”‚ en 1986 la orden de Isabel la Catâ”œâ”‚lica. Tiene, ademâ”œÃ­s, el tâ”œÂ¡tulo de barâ”œâ”‚n de Swynnerton y se sienta en la Câ”œÃ­mara de los Lores. Tras dejar a los Conservadores, estuvo con los Demâ”œâ”‚cratas, y hoy es Independiente, cualidad caracterâ”œÂ¡stica de todos los historiadores, por supuesto. Fuente visual: foto Gerardo Sancho Ramo, en AMZ.', 1976, 1976, 1976, 'Anos 70', 'UNIVERSIDAD', 41.63825200, -0.90310900, '0101000020E6100000FB2477D844E6ECBFA54DD53DB2D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33513889902.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33513889902.webp', 'https://www.flickr.com/photos/zaragozaantigua/33513889902/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22797, 'La Romareda 1976', 'Imagen capturada durante la ampliaciâ”œâ”‚n del estadio municipal de La Romareda acometida durante el verano de 1976, cuando el campo del entonces exitoso club de fâ”œâ•‘tbol de la ciudad ampliâ”œâ”‚ su aforo hasta las 43.524 localidades. La vista parcial se centra en el fondo de gol sur, recayente a la calle de Jerusalâ”œÂ®n, asâ”œÂ¡ denominada en homenaje al inmediato convento de Santa Marâ”œÂ¡a de Jerusalâ”œÂ®n, aquâ”œÂ¡ ubicado desde 1943. De fondo, algunas de las torres de viviendas del Polâ”œÂ¡gono Romareda, entre las calles de Jerusalâ”œÂ®n, y de Asâ”œÂ¡n y Palacios, con una vista parcial de la moderna parroquia de Santa Mâ”œâ”‚nica. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1976, 1976, 1976, 'Anos 70', 'UNIVERSIDAD', 41.63599900, -0.90249700, '0101000020E61000009D9E776341E1ECBFF4A44C6A68D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/45777800125.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/45777800125.webp', 'https://www.flickr.com/photos/zaragozaantigua/45777800125/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22807, 'Universidad 1976', 'Imagen capturada en el campus universitario de San Francisco el 21 de octubre de 1976 con motivo de la primera "Apertura Paralela", asâ”œÂ¡ denominada por los convocantes de las organizaciones polâ”œÂ¡ticas de la plural izquierda local, como râ”œÂ®plica alternativa a la oficial y protocolaria que se realizaba con el tradicional boato y parafernalia en el edificio de la plaza de Basilio Paraâ”œÂ¡so. Las reivindicaciones de esta jornada, muy polâ”œÂ¡ticas menos de un aâ”œâ–’o despuâ”œÂ®s de la muerte del Jefe del Estado que personificâ”œâ”‚ los â”œâ•‘ltimos cuarenta aâ”œâ–’os de la historia de Espaâ”œâ–’a, se centraron en tâ”œÂ®rminos generales en la recuperaciâ”œâ”‚n de las libertades y la democracias arrebata en 1936, la amnistâ”œÂ¡a, y la escenificaciâ”œâ”‚n de los primeros sâ”œÂ¡mbolos autonomistas desde un punto de vista no tradicionalista. Las actividades previstas, polâ”œÂ¡tico-reivindicativas y festivas, se desarrollaron en el Aula Magna de la Facultad de Ciencias y en el inmediato campus, e incluyeron las actuaciones de Joaquâ”œÂ¡n Carbonell, Eduardo Paz de La Bullonera, y el grupo de teatro El Silbo Vulnerado. La jornada festiva (no oficial, de forma que las clases continuaron, al menos en teorâ”œÂ¡a) y reivindicativa terminâ”œâ”‚ entre cargas de la Policâ”œÂ¡a Armada llamada por la Autoridad para disolverlos. En la imagen, acceso principal a la Facultad de Ciencias engalanado con carteles informativos y reivindicativos, entre los que destaca por su tamaâ”œâ–’o el de "Universidad para Aragâ”œâ”‚n" firmado por el CERZ (Comitâ”œÂ® de Estudiantes Revolucionarios de Zaragoza), ademâ”œÃ­s de ventanas de las que penden banderas varias y pancartas.', 1976, 1976, 1976, 'Anos 70', 'UNIVERSIDAD', 41.64186600, -0.89943000, '0101000020E61000002A52616C21C8ECBF093543AA28D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50241298023.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50241298023.webp', 'https://www.flickr.com/photos/zaragozaantigua/50241298023/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22921, 'Maradona 1983', 'Diego Armando Maradona (1960-2020) fue un estelar delantero de fâ”œâ•‘tbol argentino que el F.C. Barcelona fichâ”œâ”‚ en 1982 tras pagar unos inconcebibles 1.000 millones de pesetas. La imagen fue capturada en la final de la Copa del Rey (asâ”œÂ¡ denominada desde 1976 a la que desde 1939 fuera del Generalâ”œÂ¡simo) disputada en el estadio municipal de La Romareda el dâ”œÂ¡a 4 de junio de 1983, y con resultado final de F.C. Barcelona 2, Real Madrid C.F. 1. A la derecha, el Lobo Carrasco. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1983, 1983, 1983, 'Anos 80', 'UNIVERSIDAD', 41.63653100, -0.90184600, '0101000020E6100000C9E88024ECDBECBFF1F109D979D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29637855374.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29637855374.webp', 'https://www.flickr.com/photos/zaragozaantigua/29637855374/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22958, 'Salesianos 1980', 'Imagen del colegio de los Salesianos centrada en la esquina de la avenida de San Juan Bosco y la calle de Pedro Lâ”œâ”‚pez de Luna, donde destaca la piscina abierta en el gran patio. En este espacio aâ”œâ–’os despuâ”œÂ®s se construirâ”œÂ¡a el actual pabellâ”œâ”‚n polideportivo del colegio.', 1980, 1980, 1980, 'Anos 80', 'UNIVERSIDAD', 41.64452000, -0.90235900, '0101000020E61000005B0A48FB1FE0ECBF18CFA0A17FD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49915490646.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49915490646.webp', 'https://www.flickr.com/photos/zaragozaantigua/49915490646/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
