INSERT INTO public.photos VALUES (26021, 'Feria de Muestras 1983', 'â”œÃœltimos tiempos de la Feria de Muestras ubicada desde 1941 en el entonces lejano final del paseo de Fernando el Catâ”œâ”‚lico. En la imagen aâ”œÂ®rea conforma una gran manzana flanqueada por la calle de Luis Bermejo, la plaza del Emperador Carlos y la calle de Violante de Hungrâ”œÂ¡a. Al fondo, la calle de Eduardo Ibarra, el Polâ”œÂ¡gono Romareda y el Pabellâ”œâ”‚n Municipal de Deportes. En primer tâ”œÂ®rmino, denso arbolado ribereâ”œâ–’o del râ”œÂ¡o Huerva en paralelo al paseo de Isabel la Catâ”œâ”‚lica. Fuente visual: AMZ.', 1983, 1983, 1983, 'Anos 80', 'UNIVERSIDAD', 41.63732400, -0.89877800, '0101000020E61000003FA88B14CAC2ECBF5B7A34D593D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27151823487.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27151823487.webp', 'https://www.flickr.com/photos/zaragozaantigua/27151823487/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24026, 'Pilar Lorengar 1967', 'Imagen de la institucional ceremonia de descubrimiento de lâ”œÃ­pida de la nueva calle denominada "de la cantante Pilar Lorengar". La protagâ”œâ”‚nica soprano de fama internacional (Lorenza Pilar Garcâ”œÂ¡a Seta, "Pilar Lorengar" de nombre artâ”œÂ¡stico, "Loren Garcy", en su etapa de local artista de variedades), de espaldas, junto al sonriente y nunca bien ponderado alcalde Cesâ”œÃ­reo Alierta, en la esquina del final de la calle, donde desemboca en la de Corona de Aragâ”œâ”‚n. A la derecha, solares y obras de nuevos bloques en la esquina de la calle San Antonio Marâ”œÂ¡a Claret. Una vecina del inmueble disfruta de una vista privilegiada, desde un palco no oficial, entre sorprendida e intimidada. Aplausos generalizados por el respetable asistente. Debajo de la lâ”œÃ­pida descubierta, huella de la anterior placa arrancada, que identificaba hasta ese momento este vial como "calle de la Virtud". Pocos aâ”œâ–’os mâ”œÃ­s tarde, el antiguo edificio que la soportaba, el de la imagen, reliquia de las construcciones de los aâ”œâ–’os 30 de esta perifâ”œÂ®rica barriada, serâ”œÃ­ derribado, y en su lugar se levantarâ”œÃ­ uno mâ”œÃ­s moderno, vertical, y en chaflâ”œÃ­n. El actual. La ceremonial placa, desaparecida. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1967, 1967, 1967, 'Anos 60', 'UNIVERSIDAD', 41.64347100, -0.89677900, '0101000020E6100000ACAA97DF69B2ECBF5376FA415DD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24770295910.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24770295910.webp', 'https://www.flickr.com/photos/zaragozaantigua/24770295910/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24094, 'Campus universitario 1943', 'Imagen capturada durante la provechosa visita a la ciudad del ministro de Educaciâ”œâ”‚n Nacional, el turolense Josâ”œÂ® Ibâ”œÃ­â”œâ–’ez Martâ”œÂ¡n, a finales de junio de ese aâ”œâ–’o. En este caso se trata de la excursiâ”œâ”‚n realizada a los terrenos de la Ciudad Universitaria, donde tras el preceptivo homenaje religioso-castrense en la Cruz de los Estudiantes Caâ”œÂ¡dos, procediâ”œâ”‚ a participar en la colocaciâ”œâ”‚n de la primera piedra de la Casa de Gobierno de la Universidad, y asegurâ”œâ”‚ que "antes de dos aâ”œâ–’os" la Universidad de Zaragoza serâ”œÂ¡a una realidad tangible. Esta Casa de Gobierno luego no serâ”œÂ¡a realizada. Despuâ”œÂ®s visitâ”œâ”‚ las obras de la Facultad de Derecho, inaugurada en 1945, y recorriâ”œâ”‚ las instalaciones de la Facultad de Letras, donde se impartieron hasta entonces las enseâ”œâ–’anzas de ambas disciplinas.', 1943, 1943, 1943, 'Anos 40', 'UNIVERSIDAD', 41.64201800, -0.89654400, '0101000020E6100000CC99ED0A7DB0ECBFBFB854A52DD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49367380911.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49367380911.webp', 'https://www.flickr.com/photos/zaragozaantigua/49367380911/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24241, 'Ferial de atracciones c.1959', 'Nocturna imagen capturada desde la altura de la torre de la Editorial Luis Vives y centrada en el luminoso recinto de la Feria de Muestras y el anexo ferial de atracciones instalado durante las fiestas del Pilar, del que destaca el tobogâ”œÃ­n y la noria. Detrâ”œÃ­s y en penumbra, el reciente estadio municipal de La Romareda. A la izquierda, la avenida de Isabel la Catâ”œâ”‚lica. En primer tâ”œÂ®rmino, la plaza del Emperador Carlos V.', 1959, 1959, 1959, 'Anos 50', 'UNIVERSIDAD', 41.63777700, -0.89901200, '0101000020E610000009C556D0B4C4ECBF0C923EADA2D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51656772309.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51656772309.webp', 'https://www.flickr.com/photos/zaragozaantigua/51656772309/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24347, 'Santa Mâ”œâ”‚nica in the fields 1973', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo. 16/06/1973. Al fondo, las torres de viviendas del novâ”œÂ¡simo Polâ”œÂ¡gono Romareda, con su no menos moderna versiâ”œâ”‚n de lugar de culto catâ”œâ”‚lico en forma de la Parroquia de Santa Mâ”œâ”‚nica. En primer plano, los campos que producâ”œÂ¡an cereales y herbâ”œÃ­ceas, delimitados por la calle Condes de Aragâ”œâ”‚n, el Seminario y la Vâ”œÂ¡a Hispanidad, y la prolongaciâ”œâ”‚n de Juan Pablo Bonet. Era otra modalidad de barbecho urbanâ”œÂ¡stico expectante: producir hasta el â”œâ•‘ltimo momento. En la actualidad, toda esta zona estâ”œÃ­ urbanizada, construida, ingerida por la ciudad.', 1973, 1973, 1973, 'Anos 70', 'UNIVERSIDAD', 41.63812900, -0.90663400, '0101000020E61000001D226E4E2503EDBF89D00836AED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14720114960.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14720114960.webp', 'https://www.flickr.com/photos/zaragozaantigua/14720114960/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24423, 'Pedro III el Grande 1973', 'Imagen capturada en la novâ”œÂ¡sima calle de Pedro III el Grande del polâ”œÂ¡gono Romareda y centrada en el cruce con la calle de Asâ”œÂ¡n y Palacios, donde destaca la postconcilar iglesia parroquial de Santa Mâ”œâ”‚nica de la Orden de Agustinos Recoletos de San Nicolâ”œÃ­s de Tolentino, bendecida a mediados de ese aâ”œâ–’o. Confrontando con ella, algunos de los cooperativos bloques poligoneros: el nâ”œâ•‘mero 15, 17 y 21 de Asâ”œÂ¡n y Palacios, traseras del nâ”œâ•‘mero 8 de la calle de Don â”œÃ¼lvaro de Bazâ”œÃ­n y los nâ”œâ•‘meros 3 y 6 de la calle de Juan II de Aragâ”œâ”‚n. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1973, 1973, 1973, 'Anos 70', 'UNIVERSIDAD', 41.63687300, -0.90544800, '0101000020E6100000C25087156EF9ECBF4B5AF10D85D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38072978844.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38072978844.webp', 'https://www.flickr.com/photos/zaragozaantigua/38072978844/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
