INSERT INTO public.photos VALUES (26038, 'Vista aâ”œÂ®rea Isabel la Catâ”œâ”‚lica 1963', 'Vista aâ”œÂ®rea del paseo de Isabel la Catâ”œâ”‚lica, a la altura del campo de fâ”œâ•‘tbol de La Romareda y de las instalaciones de Magisterio y de la Residencia Sanitaria Josâ”œÂ® Antonio (derecha). Tras la Feria de Muestras, el cuartel Palafox. Fuente: TAF Helicâ”œâ–“pters. Arxiu Nacional de Catalunya.', 1963, 1963, 1963, 'Anos 60', 'UNIVERSIDAD', 41.63546400, -0.90113800, '0101000020E6100000E4D9E55B1FD6ECBF86E464E256D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31217218122.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31217218122.webp', 'https://www.flickr.com/photos/zaragozaantigua/31217218122/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25605, 'Corona de Aragâ”œâ”‚n 1958', 'AHPZ. Juan Mora Insa. 1958. Constructivista imagen con dos referentes de la reciente historia de la arquitectura escolar en la ciudad: el Grupo Escolar "Cervantes", al fondo, y en primerâ”œÂ¡simo pleno proceso constructivo, el nuevo edificio de la "Escuela de Maestrâ”œÂ¡a Industrial de Zaragoza", ambos en la calle Corona de Aragâ”œâ”‚n, frente por frente. El Grupo Escolar "Cervantes" fue diseâ”œâ–’ado por el arquitecto municipal Marcelo Carquâ”œÂ® e inaugurado el 14 de abril de 1933, en plâ”œÃ­stica racionalista y modernas y completas instalaciones educativas que lo convirtieron en el ejemplo mâ”œÃ­s representativo de la arquitectura escolar republicana en Zaragoza. La Escuela de Maestrâ”œÂ¡a sale de la pluma de Regino Borobio, y comenzâ”œâ”‚ su andadura en el curso 1959-60, aunque se inaugurâ”œâ”‚ con ministro en 1962. Sus formas, escuela Borobio: ladrillo caravista y aires regionalistas. En la imagen, captura del encofrado del suelo del primer piso de la Escuela de Maestrâ”œÂ¡a (actual IES "Corona de Aragâ”œâ”‚n"). Enfrente, el Grupo Escolar (actual "Casa del Estudiante" de la Universidad de Zaragoza). A la derecha, la calle Concepciâ”œâ”‚n Arenal.', 1958, 1958, 1958, 'Anos 50', 'UNIVERSIDAD', 41.64374200, -0.89754200, '0101000020E6100000732A1900AAB8ECBFE4874A2366D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15799383231.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15799383231.webp', 'https://www.flickr.com/photos/zaragozaantigua/15799383231/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25608, 'Pre-Corona de Aragâ”œâ”‚n 1928', 'En los aâ”œâ–’os 20 del pasado siglo el debate sobre las "Casas Baratas" fue muy sonado en la ciudad. Con motivo del proyecto de cubrimiento del tramo urbano del Huerva, la urbanizaciâ”œâ”‚n y recalificaciâ”œâ”‚n consecuente de terrenos aledaâ”œâ–’os y sus zonas de influencia, hizo correr mucha tinta, y crear altas expectativas de negocio. El tema de las "casa baratas", o humildes viviendas, pero dignas, para clases inferiores, se estaba incrustando en el esquema empresarial del gremio del ladrillo: por cada nueva vivienda de esas, el nâ”œâ•‘mero de viviendas "libres" (es decir, especulativas, centradas no tanto en satisfacer el derecho a una vivienda, sino en conseguir el mâ”œÃ­s alto beneficio posible por ello), era notablemente elevado. Y ello abrâ”œÂ¡a unos horizontes de grandeza inconmensurables. En el ensanche de "Miralbueno", cerca de la acequia de la Romareda y el camino de Casablanca, una zona de nueva urbanizaciâ”œâ”‚n y viales sin nombre, la Cooperativa "El Hogar de los Funcionarios de Seguridad" impulsâ”œâ”‚ la construcciâ”œâ”‚n de un conjunto de casas baratas en una barriada a la que provisionalmente dio nombre. En octubre de 1928 esta barriada fue inaugurada oficialmente, con misa de campaâ”œâ–’a (o sea, al aire libre, porque por no haber, no habâ”œÂ¡a ni iglesia cerca), bendiciâ”œâ”‚n religiosa, discursos oficiales, saludo de la madrina del proyecto, y banda de mâ”œâ•‘sica. Unos pocos aâ”œâ–’os despuâ”œÂ®s, muy cerca de aquâ”œÂ¡ serâ”œÃ­ construido el "Grupo Escolar Cervantes". En la imagen, momento de la formal inauguraciâ”œâ”‚n, con formaciâ”œâ”‚n paramilitar incluida, en un vial sin nombre que poco tiempo despuâ”œÂ®s serâ”œÃ­ denominado "calle de Lâ”œâ”‚pez Toral", y tras el 18 de julio de 1936 recibirâ”œÃ­ el nombre de "Corona de Aragâ”œâ”‚n". A principios de los aâ”œâ–’os 60, una peticiâ”œâ”‚n colectiva para desclasificarlas fue respondida favorablemente por el Ministerio de la Vivienda, y estas unifamiliares "Casa Baratas" fueron piqueteadas sin excepciâ”œâ”‚n, y sobre ellas se levantaron los desarrollistas bloques del actual tramo de Corona de Aragâ”œâ”‚n entre Pedro Cerbuna y ', 1928, 1928, 1928, 'Anos 20', 'UNIVERSIDAD', 41.64302000, -0.89649000, '0101000020E6100000001DE6CB0BB0ECBF4356B77A4ED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17315969145.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17315969145.webp', 'https://www.flickr.com/photos/zaragozaantigua/17315969145/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25615, 'Aragonia 2006', 'Obras de construcciâ”œâ”‚n del bloque de edificios Aragonia, diseâ”œâ–’ado por Rafael Moneo e inaugurado en 2009, con hotel, centro comercial, cines, oficinas y pisos de alquiler. A la izquierda, avenida de Juan Carlos I. A la derecha, avenida de Juan Pablo II, con una gasolinera a punto de ser retirada en 2006. Fuente: Archivo El Periâ”œâ”‚dico de Aragâ”œâ”‚n.', 2006, 2006, 2006, 'Siglo XXI', 'UNIVERSIDAD', 41.64011700, -0.90906500, '0101000020E610000010069E7B0F17EDBF8B4E965AEFD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21644949179.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21644949179.webp', 'https://www.flickr.com/photos/zaragozaantigua/21644949179/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25618, 'Romareda 1956', 'Imagen de actuaciones preliminares en la ubicaciâ”œâ”‚n del nuevo Estadio Municipal de fâ”œâ•‘tbol entre el recinto Ferial y la Residencia Sanitaria "Josâ”œÂ® Antonio". La preferencia de su denominaciâ”œâ”‚n, tras un proceso participativo y horizontal por medio de una publicaciâ”œâ”‚n deportiva local, parecâ”œÂ¡a ser claramente la de "Estadio de Miralbueno", por ser ese el tâ”œÂ®rmino agrâ”œÂ¡cola de ubicaciâ”œâ”‚n ("Miralbueno el Viejo"), aunque otras voces sugerâ”œÂ¡an utilizar la referencia del antiguo e importante flujo de la acequia de "la Romareda". Esta batalla mental sumiâ”œâ”‚ a la ciudad en un encendido debate, en tiempos en que apenas si debâ”œÂ¡an pasar otras cosas dignas de ponerse en los papeles. En la imagen, captura de las obras desde la calle de Jerusalâ”œÂ®n. Al fondo, la mole de la nueva Residencia Sanitaria "Josâ”œÂ® Antonio", tras el paseo de Isabel la Catâ”œâ”‚lica. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1956, 1956, 1956, 'Anos 50', 'UNIVERSIDAD', 41.63587800, -0.90170300, '0101000020E61000001590F63FC0DAECBF791F477364D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23850035330.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23850035330.webp', 'https://www.flickr.com/photos/zaragozaantigua/23850035330/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25621, 'Casa Grande 1975', 'Desde las notorias alturas de uno de los novâ”œÂ¡simos bloques habitacionales del polâ”œÂ¡gono Romareda (esquina calle de Jerusalâ”œÂ®n con Juan II de Aragâ”œâ”‚n), un vistazo casi de conjunto de la original "Residencia Sanitaria Josâ”œÂ® Antonio", luego denominada "Residencia General de la Ciudad Sanitaria de la Seguridad Social de Zaragoza", e intitulada desde muy pronto por el antropolâ”œâ”‚gico conceptismo local como "Casa Grande", justo antes del inicio de unas importantes obras de ampliaciâ”œâ”‚n y reforma acometidas por "Dragados y Construcciones S.A.", la principal empresa de obras pâ”œâ•‘blicas del Reino de Espaâ”œâ–’a desde 1951. A la izquierda, un pedazo del Estadio Municipal de la Romareda, tal y como era. Al fondo, la megaurbanizaciâ”œâ”‚n de los megabloques de la inmobiliaria Marvel S.A., oficialmente "Ciudad Residencial Parque Buenavista". Despuntan, allâ”œÃ­ donde la antigua playa del Canal Imperial, la câ”œâ•‘pula de la iglesia de San Fernando, y la demediada torre del "Sacrario Militare Italiano", propiedad del gobierno de esa repâ”œâ•‘blica. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1975, 1975, 1975, 'Anos 70', 'UNIVERSIDAD', 41.63541400, -0.90057700, '0101000020E61000000EF450DB86D1ECBFD4B5F63E55D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24407779922.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24407779922.webp', 'https://www.flickr.com/photos/zaragozaantigua/24407779922/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25623, 'Pl. del Emperador Carlos 1974', 'Imagen de la unidad 208 de la tranviaria lâ”œÂ¡nea 11, "Parque-San Josâ”œÂ®", en la terminal de la plaza del Emperador Carlos, preparada para iniciar su recorrido hacia el barrio de San Josâ”œÂ®. Al fondo, a la izquierda, la torre de los talleres de la editorial Luis Vives, en el paseo de Fernando el Catâ”œâ”‚lico. Al fondo, a la derecha, el puente del Trece de Septiembre (conmemoraciâ”œâ”‚n de la fecha del golpe de Estado que, aprobado por la Corona, dio inicio a la dictadura del general Primo de Rivera). Por encima de la vegetaciâ”œâ”‚n arbâ”œâ”‚rea del parque de Primo de Rivera, a la derecha extrema de la imagen, emergen los nuevos bloques MARVEL de la calle del Arzobispo Morcillo. Fuente visual: www.forotrenes.com/', 1974, 1974, 1974, 'Anos 70', 'UNIVERSIDAD', 41.63776300, -0.89858100, '0101000020E6100000BFD2F9F02CC1ECBFA7CCCD37A2D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31143561466.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31143561466.webp', 'https://www.flickr.com/photos/zaragozaantigua/31143561466/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25624, 'Distrito Universidad 2005', 'Foto: Josâ”œÂ® Miguel Marco. Vista del solar ubicado entre las avenidas de Juan Carlos I y Juan Pablo ll, al comienzo de las obras de construcciâ”œâ”‚n del bloque de edificios Aragonia, de Rafael Moneo. La gasolinera de la derecha serâ”œÃ­ retirada en 2006, y el complejo inaugurado en 2009. Fuente: Heraldo de Aragâ”œâ”‚n.', 2005, 2005, 2005, 'Siglo XXI', 'UNIVERSIDAD', 41.64018700, -0.90920600, '0101000020E610000096766A2E3718EDBF8429CAA5F1D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31393458200.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31393458200.webp', 'https://www.flickr.com/photos/zaragozaantigua/31393458200/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25625, 'Calle Eduardo Ibarra 2006', 'Foto: Juan Carlos Arcos. Vista de la obra de excavaciâ”œâ”‚n para aparcamiento subterrâ”œÃ­neo en la calle de Eduardo Ibarra, en noviembre de 2006. Aparcamiento y plaza sobre â”œÂ®l, serâ”œÃ­n inaugurados en 2008. Al fondo, campo de fâ”œâ•‘tbol de La Romareda y hospital Miguel Servet. Fuente: Heraldo de Aragâ”œâ”‚n.', 2006, 2006, 2006, 'Siglo XXI', 'UNIVERSIDAD', 41.63714000, -0.90314400, '0101000020E61000001684F23E8EE6ECBF9A7CB3CD8DD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31976113892.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31976113892.webp', 'https://www.flickr.com/photos/zaragozaantigua/31976113892/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26055, 'Audiorama 1991', 'Vista en septiembre de 1991 de los antiguos terrenos de la Feria de Muestras, al inicio de las obras de construcciâ”œâ”‚n del complejo Audiorama (1994), que incluirâ”œÃ­ el Auditorio, la Sala Multiusos y un centro comercial. A la derecha, el hospital Miguel Servet. Fuente: Colecciâ”œâ”‚n particular.', 1991, 1991, 1991, 'Anos 90', 'UNIVERSIDAD', 41.63822700, -0.90120500, '0101000020E6100000D8BB3FDEABD6ECBF4C361E6CB1D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32483803854.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32483803854.webp', 'https://www.flickr.com/photos/zaragozaantigua/32483803854/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25639, 'Campus universitario 1970', 'Imagen capturada en el campus universitario de San Francisco ante el "Monumento a los Escolares muertos por Dios y por Espaâ”œâ–’a 1936-39" y realizada con motivo de la detenciâ”œâ”‚n de seis miembros de las juventudes de las Comisiones Obreras por la realizaciâ”œâ”‚n de pintadas subversivas contra el proyecto de Ley Sindical del râ”œÂ®gimen franquista que serâ”œÂ¡a finalmente aprobado en 1971. En primer tâ”œÂ®rmino, el referido memorial con pintadas. Una de ellas, "Franco y Carrero asesinos", se refiere al presidente y vicepresidente del Gobierno, respectivamente, posiblemente en recuerdo del asesinato del estudiante Enrique Ruano Casanova, que el aâ”œâ–’o anterior "se habâ”œÂ¡a suicidado", segâ”œâ•‘n la versiâ”œâ”‚n oficial de los sucesos, "tirâ”œÃ­ndose" desde el sâ”œÂ®ptimo piso de un inmueble donde estaba custodiado por la Brigada Polâ”œÂ¡tico Social. Tras el monumento emerge el tejado de uno de los pabellones de la Escuela de Maestrâ”œÂ¡a Industrial de Zaragoza. El entorno edilicio muestra, al fondo, el temporal "vacâ”œÂ¡o" entre los esquineros inmuebles del nâ”¬â•‘ 38 de la calle de la Corona de Aragâ”œâ”‚n, a la izquierda y esquinero con la de la cantante Pilar Lorengar, y el nâ”¬â•‘ 67 de la calle de San Antonio Marâ”œÂ¡a Claret a la derecha. Un poco antes y tambiâ”œÂ®n a la derecha, aspecto de los antiguos inmuebles de esa misma calle entre los nâ”œâ•‘meros 61 a 65, luego sustituidos por otros mâ”œÃ­s modernos, antecedidos del mâ”œÃ­s reciente nâ”¬â•‘ 67, esquinero con la calle de Menâ”œÂ®ndez y Pelayo.', 1970, 1970, 1970, 'Anos 70', 'UNIVERSIDAD', 41.64264400, -0.89731600, '0101000020E610000060AE450BD0B6ECBF3D7C992842D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50299001616.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50299001616.webp', 'https://www.flickr.com/photos/zaragozaantigua/50299001616/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25643, 'Ciudad Universitaria 1935', 'Imagen capturada durante el inicio de las obras de la Ciudad Universitaria proyectada en el ensanche de Miralbueno, entorno de la nueva plaza de Espaâ”œâ–’a, redenominada en 1937 de San Francisco. La escena muestra la zona delimitada para el edificio de la Facultad de Filosofâ”œÂ¡a y Letras junto al camino y cauce al aire de la acequia de La Romareda (a la derecha y fuera de plano) y frontera con terrenos del Cuartel de Artillerâ”œÂ¡a de Palafox (a espaldas del fotâ”œâ”‚grafo). Hacia el fondo, edificios de la zona en expansiâ”œâ”‚n urbana vertebrada entre las calles de Lâ”œâ”‚pez Toral y del Carmen, al fondo de la cual se perfila la câ”œâ•‘pula de la iglesia parroquial de Santiago recayente a la calle de san Ildefonso. A la derecha emerge el monumental frontâ”œâ”‚n del bloque de seis plantas de viviendas econâ”œâ”‚micas construido en la manzana 50 del ensanche de Casas Baratas, proyectado por el arquitecto Secundino Zuazo Ugalde y construido por la Sociedad Zaragozana de Urbanizaciâ”œâ”‚n y Construcciâ”œâ”‚n en 1930.', 1935, 1935, 1935, 'Anos 30', 'UNIVERSIDAD', 41.64080800, -0.89776700, '0101000020E610000070B20DDC81BAECBFF1811DFF05D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54953026198.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54953026198.webp', 'https://www.flickr.com/photos/zaragozaantigua/54953026198/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25863, 'Calle Violante de Hungrâ”œÂ¡a 1988', 'Vista de la calle de Violante de Hungrâ”œÂ¡a de Zaragoza desde la plaza del Emperador Carlos, en 1988. El recinto de la Feria de Muestras (en el centro de la imagen) ya estâ”œÃ­ sentenciado desde 1985: se anuncia la construcciâ”œâ”‚n del complejo Audiorama, "un innovador centro cultural, festival, comercial y hotelero". Fuente: Revista Nuestra Zaragoza, 1988.', 1988, 1988, 1988, 'Anos 80', 'UNIVERSIDAD', 41.63833700, -0.89966700, '0101000020E6100000384BC97212CAECBFD369DD06B5D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22290854269.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22290854269.webp', 'https://www.flickr.com/photos/zaragozaantigua/22290854269/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25968, 'Feria de Muestras 1956', '1956. Aâ”œÂ®rea vista del entorno del recinto de la Feria de Muestras y la "Residencia Sanitaria Josâ”œÂ® Antonio". La imagen estâ”œÃ­ tomada en otro momento crâ”œÂ¡tico: los meses transcurridos entre la inauguraciâ”œâ”‚n de la "Casa Grande", en 1955, y el comienzo de las obras del que serâ”œÂ¡a Estadio Municipal de la Romareda, a finales de 1956. De momento, la acequia de la Romareda sigue fluyendo, entre campos de herbâ”œÃ­ceas, aunque ya han comenzado excavaciones exploratorias. â”œÃ¼mbitos de atenciâ”œâ”‚n: en primer plano, los casi 34.000 m2 del Cuartel de Artillerâ”œÂ¡a de Palafox; el reciente recinto de la Feria de Muestras, inaugurado en 1941; la Editorial Luis Vives, con su torre, pero sin linterna, y con el Huerva a sus espaldas; el Puente 13 de Septiembre y el acceso al enorme Parque Primo de Rivera; la Estatua del Batallador, en el Cabezo de Buena Vista, que se ve de lo grande que es, no como el exiliado Neptuno; a la izquierda, la harinera "La Imperial de Aragâ”œâ”‚n", junto al Canal Imperial; el Hospital San Juan de Dios, inaugurado en 1953; al otro lado del Canal, el barrio de Torrero, con su remate en la câ”œÃ­rcel, primero, y en el Cementerio catâ”œâ”‚lico, luego. Mâ”œÃ­s arriba, la Plana de Zaragoza. Et caetera... Sin olvidar, en primerâ”œÂ¡simo plano, el ala del aeroplano. â”¬Ã­Ah, y el Rincâ”œâ”‚n de Goya, customizado por el Râ”œÂ®gimen como Colegio Pâ”œâ•‘blico (femenino) San Benito!', 1956, 1956, 1956, 'Anos 50', 'UNIVERSIDAD', 41.63733500, -0.89907500, '0101000020E6100000A1D634EF38C5ECBF4FCC7A3194D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14797959560.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14797959560.webp', 'https://www.flickr.com/photos/zaragozaantigua/14797959560/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLI