INSERT INTO public.photos VALUES (25981, 'Campus San Francisco 1975', 'Archivo Municipal Zaragoza. Gerardo Sancho Ramo. 13/04/1975. Aâ”œÂ®rea vista panorâ”œÃ­mica de la ciudad, con imagen parcial del Campus de la Plaza de San Francisco, en primer plano: la Facultad de Ciencias y, a la derecha, el nuevo Edificio Interfacultades, con su estanque y jardines. Justo detrâ”œÃ­s del "Inter" estaba aâ”œâ•‘n el "Monumento a los estudiantes caâ”œÂ¡dos por Dios y por Espaâ”œâ–’a", aquâ”œÂ¡ (bien) tapado. Detrâ”œÃ­s, el telâ”œâ”‚n de fondo de la ciudad, con una destacable presencia de altos y recientes edificios, como el "Torresol", a la izquierda.', 1975, 1975, 1975, 'Anos 70', 'UNIVERSIDAD', 41.64240300, -0.89909700, '0101000020E610000096D05D1267C5ECBF18EDF1423AD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15247697556.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15247697556.webp', 'https://www.flickr.com/photos/zaragozaantigua/15247697556/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
