INSERT INTO public.photos VALUES (24036, '&quot;Dâ”œÂ¡a del Ebro&quot; 1987', 'El 31 de mayo de 1987, Antonio Gonzâ”œÃ­lez Triviâ”œâ–’o, alcalde de la ciudad en funciones, y en plena campaâ”œâ–’a electoral previa a las elecciones municipales de ese aâ”œâ–’o, en las que figuraba como destacada cabeza de lista de la candidatura del PSOE, inaugurâ”œâ”‚ el "Monumento al Ebro" sito en Vadorrey, el parque donde se emplazaba, y un cercano campo de fâ”œâ•‘tbol. Ademâ”œÃ­s, instituyâ”œâ”‚ oficialmente el "Dâ”œÂ¡a del Ebro", una de esas celebraciones tan zaragozanas cuya "tradicional" seâ”œâ–’a de identidad es una "regata" cuya primera ediciâ”œâ”‚n tuvo lugar en 1995, que consiste en reivindicar la navegabilidad del Ebro tal y como la practicaban los vikingos, por medio de una competiciâ”œâ”‚n amistosa entre dos embarcaciones de grandes dimensiones. En la imagen, el popular (cuando esta palabra no tenâ”œÂ¡a adscripciâ”œâ”‚n partidista) alcalde en funciones, y firme candidato a alcalde, firma la donaciâ”œâ”‚n pâ”œâ•‘blica del Monumento al Ebro, consistente en un antiguo remolcador del Canal Imperial de Aragâ”œâ”‚n, salvado de la chatarra, restaurado, y ornamentado como elemento central de un estanque de agua. De telâ”œâ”‚n de fondo, en la margen derecha del Ebro, bloques del paseo de Echegaray y Caballero, de la calle Josâ”œÂ® Martâ”œÂ¡nez Ruiz, e incluso del descomunal "Hâ”œÃ­bitat 2000", cerca de la calle Asalto. Fuente visual: "Historia resumida de una Asociaciâ”œâ”‚n Vecinal, VADORREY" (sic).', 1987, 1987, 1987, 'Anos 80', 'LAS FUENTES', 41.65312100, -0.85630100, '0101000020E6100000EE06D15AD166EBBF58AA0B7899D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30026788683.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30026788683.webp', 'https://www.flickr.com/photos/zaragozaantigua/30026788683/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24370, 'Torre Ramona c.1968', 'El edificio blanco del fondo -la Torre Ramona- fue reformatorio El Buen Pastor entre 1917 y 1955. Despuâ”œÂ®s fue ocupado por el colegio de monjas de la Pâ”œÂ¡a Uniâ”œâ”‚n de Nuestra Seâ”œâ–’ora del Pilar para Hispanoamâ”œÂ®rica y Filipinas. En primer plano, infraviviendas o chabolas, a la espera de que aâ”œâ–’os despuâ”œÂ®s el solar albergase el parque Torre Ramona, en el barrio de Las Fuentes.', 1968, 1968, 1968, 'Anos 60', 'LAS FUENTES', 41.64094400, -0.86212600, '0101000020E61000006000E1438996EBBFA148F7730AD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15557383790.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15557383790.webp', 'https://www.flickr.com/photos/zaragozaantigua/15557383790/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24372, 'Reformatorio Buen Pastor 1932', 'Juan Mora. 1932 Een 1901 Francisco Andrâ”œÂ®s Olivâ”œÃ­n cediâ”œâ”‚ trece hectâ”œÃ­reas de terreno de su Torre Guallart/Torre Ramona al Hospicio y al Hospital de Zaragoza, dependientes de la Diputaciâ”œâ”‚n. En 1905 abrâ”œÂ¡a allâ”œÂ¡ la Escuela de Agricultura Prâ”œÃ­ctica Regional para niâ”œâ–’os del hospicio y labradores pobres, y en 1912 se instalaba en el edificio principal el Ã”Ã‡Â£manicomio para alienados distinguidosÃ”Ã‡Ã˜ de Nuestra Seâ”œâ–’ora del Pilar y en 1914 la Diputaciâ”œâ”‚n cedâ”œÂ¡a al Estado la finca, que mâ”œÃ­s tarde albergarâ”œÂ¡a tambiâ”œÂ®n un reformatorio, a cambio de que asumiera el mantenimiento del centro psiquiâ”œÃ­trico. En 1917 el Gobernador Civil gestionâ”œâ”‚ la cesiâ”œâ”‚n estatal, a cambio de un alquiler, de la "Torre Ramona" para Reformatorio de Menores. Los Terciarios Capuchinos de Nâ”¬Â¬ Seâ”œâ–’ora de los Dolores fueron designados como personal. El edificio fue acondicionado, segâ”œâ•‘n proyecto del arquitecto Borobio, como una granja de reeducaciâ”œâ”‚n para 70 muchachos abandonados o delincuentes (??), con talleres de carpinterâ”œÂ¡a, cerrajerâ”œÂ¡a, alpargaterâ”œÂ¡a, agricultura y jardinerâ”œÂ¡a. Este Reformatorio fue clausurado en 1955 y trasladado a Valdefierro, y en 1960 se instalaron las religiosas de Nuestra Seâ”œâ–’ora del Pilar y Santiago Apâ”œâ”‚stol, hasta 2014. Desde 2010 su propietario es el Gobierno de Aragâ”œâ”‚n, que valorâ”œâ”‚ que Ã”Ã‡Â£el edificio se encuentra en estado ruinoso, tiene problemas y genera riesgoÃ”Ã‡Ã˜ previâ”œâ”‚ en esta ubicaciâ”œâ”‚n un â”œÃ­rea residencial con equipamientos verdes. En mayo de 2024 tuvo lugar la demoliciâ”œâ”‚n del antiguo reformatorio del Buen Pastor en Torre Ramona, conocido como centro de las religiosas misioneras de Nuestra Seâ”œâ–’ora del Pilar, salvo las zonas catalogadas de la capilla, las bodegas y los jardines. En la imagen, el edificio del Reformatorio, y un aspecto de la huerta de los alrededores (actual calle Marâ”œÂ¡a de Aragâ”œâ”‚n). Fuente visual: "Aragâ”œâ”‚n : revista grâ”œÃ­fica de cultura aragonesa" (Aâ”œâ–’o VIII, Nâ”¬â•‘ 80, mayo 1932).', 1932, 1932, 1932, 'Anos 30', 'LAS FUENTES', 41.64094400, -0.86212600, '0101000020E61000006000E1438996EBBFA148F7730AD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15675814615.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15675814615.webp', 'https://www.flickr.com/photos/zaragozaantigua/15675814615/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
