INSERT INTO public.photos VALUES (24435, 'GIESA aâ”œâ–’os 40', 'El prâ”œâ”‚cer Joaquâ”œÂ¡n Guiral Lascellas adquiriâ”œâ”‚ en 1914 la empresa de Antonio Abiâ”œÃ­n e Hijo dedicada a Proyectos e Instalaciones Elâ”œÂ®ctricas. De la calle de Roda pasâ”œâ”‚ a la calle de San Jorge, esquina con la San Andrâ”œÂ®s para, en 1937, mudarse a la Avenida de San Josâ”œÂ® 32. En 1940, la empresa paso a denominarse "Guiral Industrias Elâ”œÂ®ctricas S.A." (GIESA). En 1942 comprâ”œâ”‚ los terrenos denominados "Villa Asunciâ”œâ”‚n", en el km. 2 de la carretera de Zaragoza a Castellâ”œâ”‚n, para levantar unas nuevas y mucho mâ”œÃ­s extensas instalaciones industriales, inauguradas en 1945. En la imagen, traseras del complejo de naves e instalaciones de GIESA en Miguel Servet. A la izquierda sobresale el abandonado Palacio Larrinaga. Justo enfrente, tapada por la fâ”œÃ­brica, la Estaciâ”œâ”‚n de ferrocarril de Utrillas, con la que tenâ”œÂ¡a acceso directo a travâ”œÂ®s de una vâ”œÂ¡a de servicio propia, atravesando Miguel Servet.', 1940, 1940, 1949, 'Anos 40', 'LAS FUENTES', 41.64026200, -0.86289800, '0101000020E6100000F5143944DC9CEBBF8F6FEF1AF4D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14791448609.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14791448609.webp', 'https://www.flickr.com/photos/zaragozaantigua/14791448609/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
